pub fn path_sum(root: Option<Box<TreeNode>>, target_sum: i32) -> i32 {
    use std::collections::HashMap;
    let mut prefix: HashMap<i64, i32> = HashMap::new();
    prefix.insert(0, 1);
    fn dfs(node: &Option<Box<TreeNode>>, curr_sum: i64, target: i64, prefix: &mut HashMap<i64, i32>) -> i32 {
        match node {
            None => 0,
            Some(n) => {
                let curr_sum = curr_sum + n.val as i64;
                let mut count = *prefix.get(&(curr_sum - target)).unwrap_or(&0);
                *prefix.entry(curr_sum).or_insert(0) += 1;
                count += dfs(&n.left, curr_sum, target, prefix);
                count += dfs(&n.right, curr_sum, target, prefix);
                *prefix.get_mut(&curr_sum).unwrap() -= 1;
                count
            }
        }
    }
    dfs(&root, 0, target_sum as i64, &mut prefix)
}

